create table wksp_arunext.mtg_locations (
    location_id   number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    location_type varchar2(20 char) not null enable,
    name          varchar2(200 char) not null enable,
    description   varchar2(1000 char),
    active_yn     varchar2(1 char) default 'Y' not null enable,
    created_at    timestamp(6) with time zone default systimestamp not null enable,
    updated_at    timestamp(6) with time zone
);

alter table wksp_arunext.mtg_locations
    add constraint mtg_locations_active_ck
        check ( active_yn in ( 'Y', 'N' ) ) enable;

alter table wksp_arunext.mtg_locations
    add constraint mtg_locations_name_uk unique ( location_type,
                                                  name )
        using index enable;

alter table wksp_arunext.mtg_locations
    add constraint mtg_locations_pk primary key ( location_id )
        using index enable;

alter table wksp_arunext.mtg_locations
    add constraint mtg_locations_type_ck
        check ( location_type in ( 'STORAGE', 'DECK' ) ) enable;


